returns.description:
A health status payload with structure:
  {
    status: 'healthy' | 'unhealthy',
    timestamp: ISO string,
    githubCli: {
      installed: boolean,
      authenticated: boolean,
      versionOk: boolean,
      version: string | null,
      details: string[]
    },
    runtimeFreshness: {
      status: 'current' | 'stale' | 'unknown',
      stale: object,
      details: string[],
      hint: string | null
    }
  }
